const filterItems = $('When Executed by Another Workflow').all();

let caption = '';
let chatId = null;
const imageParts = [];

for (let i = 0; i < filterItems.length; i++) {
  const filterItem = filterItems[i];
  if (!caption && filterItem.json.caption) caption = filterItem.json.caption;
  if (!chatId) chatId = filterItem.json.chat_id;

  const mimeType = filterItem.json.mime_type || 'image/jpeg';

  if (mimeType === 'text/plain') {
    // 纯文字消息，直接当text part传给Gemini
    imageParts.push({
      text: `以下是菜单文字内容：\n${filterItem.json.text_content}`
    });
  } else {
    // 照片或PDF，从HTTP Request2拿binary数据
    const binaryDataBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const base64Data = binaryDataBuffer.toString('base64');
    imageParts.push({
      inline_data: {
        mime_type: mimeType,
        data: base64Data
      }
    });
  }
}

const geminiRequest = {
  contents: [{
    parts: [
      {
        text: `你是一个POS系统商品导入助手。以下是用户的备注规则：\n${caption}\n\n请根据以下所有菜单图片/文字/文件提取全部商品，合并成一个列表，严格只输出JSON，不要任何解释文字：\n{"items":[{"name":"商品名","category":"分类","spec":"规格","stock_qty":0,"cost_price":0,"sell_price":0.00}],"flagged":[]}`
      },
      ...imageParts
    ]
  }]
};

return [{
  json: {
    chatId: chatId,
    caption: caption,
    photoCount: filterItems.length,
    geminiRequest: geminiRequest
  }
}];

