// 检查Gemini是否失败
const firstItem = $input.first();
if (firstItem.json.error) {
  const chatId = $('Code in JavaScript1').first().json.chatId;
  const errMsg = firstItem.json.error.message || '';
  let reason = 'AI 服务暂时出现问题，请稍后重试。';
  if (errMsg.includes('unavailable') || errMsg.includes('overload') || errMsg.includes('high demand')) {
    reason = 'AI 服务器目前流量过高，请等待约 1 分钟后重新发送。';
  } else if (errMsg.includes('quota') || errMsg.includes('rate')) {
    reason = 'AI 请求次数已达上限，请等待约 1 分钟后重新发送。';
  }
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot你的TOKEN/sendMessage`,
    headers: { 'Content-Type': 'application/json' },
    body: { chat_id: chatId, text: `❌ 处理失败：${reason}` },
    json: true
  });
  return [];
}

