const ExcelJS = require('exceljs');

// 收集所有照片的Gemini识别结果
const allItems = [];
const allFlagged = [];
let chatId = null;

for (const item of $input.all()) {
  // 先检查这个item是不是Gemini请求失败留下的错误
  if (item.json.error || !item.json.candidates) {
    const failedChatId = $('Code in JavaScript1').first().json.chatId;
    const errMsg = item.json.error?.message || 'Gemini请求失败，请稍等一下再试一次（可能是请求太频繁）。';
    if (failedChatId) {
      try {
        await this.helpers.httpRequest({
          method: 'POST',
          url: `https://api.telegram.org/botYOUR_TELEGRAM_BOT_TOKEN/sendMessage`,
          headers: { 'Content-Type': 'application/json' },
          body: { chat_id: failedChatId, text: `⚠️ 识别失败：${errMsg}` },
          json: true
        });
      } catch (e) { /* 通知失败也不要让整个节点崩 */ }
    }
    return [];
  }
  const rawText = item.json.candidates[0].content.parts[0].text;
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  allItems.push(...parsed.items);
  if (parsed.flagged) allFlagged.push(...parsed.flagged);
}

// 从上游节点拿chat_id
chatId = $('Code in JavaScript1').first().json.chatId;

// 生成xlsx
const workbook = new ExcelJS.Workbook();
const ws = workbook.addWorksheet('Sheet1');

const headers = [
  '名称（必填）','分类（必填）','条码','规格','主单位','库存量',
  '进货价（必填）','销售价（必填）','毛利率','批发价','会员价','会员折扣',
  '积分商品','库存上限','库存下限','品牌','供货商','生产日期','保质期',
  '拼音码','标签打印','自定义2','自定义3','商品状态','商品描述','不计库存',
  'NORMAL售价','2%售价','SILVER售价','FOOD PANDA售价','Staff售价','VIP售价',
  'Business Owner售价','gold售价','VVIP售价','demo售价','New Member售价',
  'member售价','COCKTAILS售价','1 MONTH售价','2 MONTHS售价','EXPIRED售价','香江等级售价'
];

headers.forEach((h, i) => {
  ws.getCell(1, i + 1).value = h;
});

allItems.forEach((item, rowIdx) => {
  const r = rowIdx + 2;
  ws.getCell(r, 1).value = item.name || '';
  ws.getCell(r, 2).value = item.category || '';
  ws.getCell(r, 4).value = item.spec || '';
  ws.getCell(r, 6).value = item.stock_qty ?? 0;
  ws.getCell(r, 7).value = item.cost_price ?? 0;
  ws.getCell(r, 8).value = Number(item.sell_price) || 0;
  ws.getCell(r, 8).numFmt = '0.00';
});

const buffer = await workbook.xlsx.writeBuffer();
const base64 = buffer.toString('base64');

return [{
  json: {
    chat_id: chatId,
    itemCount: allItems.length,
    photoCount: $input.all().length,
    flagged: allFlagged
  },
  binary: {
    file: {
      data: base64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: 'menu_import.xlsx'
    }
  }
}];

// 这个workflow现在不用管锁了（Gemini慢不会再拖累接待员），
// 只需要把items原样传下去给发送文件的节点
return $input.all();
